  const record = JSON.parse(fs.readFileSync(uploadPath, "utf8"));
  record.upload.expires_at = Math.floor(Date.now() / 1000) - 1;
  fs.writeFileSync(uploadPath, `${JSON.stringify(record, null, 2)}\n`);
