async function withTemporaryExecutableBin(commands, run) {
  const binDir = fs.mkdtempSync(path.join(os.tmpdir(), "open-codex-test-bin-"));
  const previousPath = process.env.PATH;
  try {
    for (const [name, script] of Object.entries(commands)) {
      const filePath = path.join(binDir, name);
      fs.writeFileSync(filePath, script, { mode: 0o700 });
    }
    process.env.PATH = `${binDir}${path.delimiter}${previousPath || ""}`;
    return await run();
  } finally {
    if (previousPath === undefined) delete process.env.PATH;
    else process.env.PATH = previousPath;
    fs.rmSync(binDir, { recursive: true, force: true });
  }
}

async function withMockProvider(handler, run, configOverrides = {}) {
  const requests = [];
  const provider = http.createServer(async (req, res) => {
    const chunks = [];
    for await (const chunk of req) chunks.push(Buffer.from(chunk));
    const rawBody = Buffer.concat(chunks).toString("utf8");
    let body = null;
    if (rawBody) {
      try {
        body = JSON.parse(rawBody);
      } catch {
        body = null;
      }
    }
    requests.push({ req, body, rawBody });
    await handler(req, res, requests.at(-1));
  });
  const providerAddress = await listen(provider);

  const stateDir = fs.mkdtempSync(path.join(os.tmpdir(), "open-codex-bridge-"));
  const config = loadConfig({
    providerBaseUrl: `http://127.0.0.1:${providerAddress.port}`,
    providerApiKey: "test-key",
    defaultModel: "mock-model",
    stateDir,
    ...(typeof configOverrides === "function"
      ? configOverrides({ providerAddress, stateDir })
      : configOverrides),
  });
  const bridge = createServer(config);
  const bridgeAddress = await listen(bridge);

  try {
    await run({ bridgeAddress, providerAddress, requests, stateDir });
  } finally {
    await close(bridge);
    await close(provider);
    fs.rmSync(stateDir, { recursive: true, force: true });
  }
}

function parseSseEvents(text) {
  return text
    .split(/\n\n/)
    .filter((frame) => frame.trim())
    .map((frame) => {
      const lines = frame.split(/\r?\n/);
      const event = lines.find((line) => line.startsWith("event:"))?.slice(6).trim() || "message";
      const data = lines
        .filter((line) => line.startsWith("data:"))
        .map((line) => line.slice(5).trimStart())
        .join("\n");
      return { event, data: data === "[DONE]" ? data : data ? JSON.parse(data) : null };
    });
}

function tinyPdfBuffer(text) {
  const escaped = String(text)
    .replace(/\\/g, "\\\\")
    .replace(/\(/g, "\\(")
    .replace(/\)/g, "\\)");
  const objects = [
    "<< /Type /Catalog /Pages 2 0 R >>",
    "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
    "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 4 0 R >> >> /Contents 5 0 R >>",
    "<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
  ];
  const stream = `BT\n/F1 18 Tf\n72 720 Td\n(${escaped}) Tj\nET\n`;
  objects.push(`<< /Length ${Buffer.byteLength(stream, "ascii")} >>\nstream\n${stream}endstream`);

  let pdf = "%PDF-1.4\n";
  const offsets = [0];
  objects.forEach((object, index) => {
    offsets.push(Buffer.byteLength(pdf, "ascii"));
    pdf += `${index + 1} 0 obj\n${object}\nendobj\n`;
  });
  const xrefOffset = Buffer.byteLength(pdf, "ascii");
  pdf += `xref\n0 ${objects.length + 1}\n`;
  pdf += "0000000000 65535 f \n";
  for (let index = 1; index <= objects.length; index += 1) {
    pdf += `${String(offsets[index]).padStart(10, "0")} 00000 n \n`;
  }
  pdf += `trailer\n<< /Size ${objects.length + 1} /Root 1 0 R >>\nstartxref\n${xrefOffset}\n%%EOF\n`;
  return Buffer.from(pdf, "ascii");
}

function tinyZipBuffer(entries, options = {}) {
  const locals = [];
  const centrals = [];
  let offset = 0;
  const method = options.deflate ? 8 : 0;
  for (const [name, content] of Object.entries(entries)) {
    const nameBuffer = Buffer.from(name, "utf8");
    const data = Buffer.isBuffer(content) ? content : Buffer.from(String(content), "utf8");
    const compressed = method === 8 ? zlib.deflateRawSync(data) : data;
    const crc = crc32(data);

    const local = Buffer.alloc(30);
    local.writeUInt32LE(0x04034b50, 0);
    local.writeUInt16LE(20, 4);
    local.writeUInt16LE(0, 6);
    local.writeUInt16LE(method, 8);
    local.writeUInt16LE(0, 10);
    local.writeUInt16LE(0, 12);
    local.writeUInt32LE(crc, 14);
    local.writeUInt32LE(compressed.length, 18);
    local.writeUInt32LE(data.length, 22);
    local.writeUInt16LE(nameBuffer.length, 26);
    local.writeUInt16LE(0, 28);
    locals.push(local, nameBuffer, compressed);

    const central = Buffer.alloc(46);
    central.writeUInt32LE(0x02014b50, 0);
    central.writeUInt16LE(20, 4);
    central.writeUInt16LE(20, 6);
    central.writeUInt16LE(0, 8);
    central.writeUInt16LE(method, 10);
    central.writeUInt16LE(0, 12);
    central.writeUInt16LE(0, 14);
    central.writeUInt32LE(crc, 16);
    central.writeUInt32LE(compressed.length, 20);
    central.writeUInt32LE(data.length, 24);
    central.writeUInt16LE(nameBuffer.length, 28);
    central.writeUInt16LE(0, 30);
    central.writeUInt16LE(0, 32);
    central.writeUInt16LE(0, 34);
    central.writeUInt16LE(0, 36);
    central.writeUInt32LE(0, 38);
    central.writeUInt32LE(offset, 42);
    centrals.push(central, nameBuffer);

    offset += local.length + nameBuffer.length + compressed.length;
  }

  const centralDir = Buffer.concat(centrals);
  const end = Buffer.alloc(22);
  end.writeUInt32LE(0x06054b50, 0);
  end.writeUInt16LE(0, 4);
  end.writeUInt16LE(0, 6);
  end.writeUInt16LE(Object.keys(entries).length, 8);
  end.writeUInt16LE(Object.keys(entries).length, 10);
  end.writeUInt32LE(centralDir.length, 12);
  end.writeUInt32LE(offset, 16);
  end.writeUInt16LE(0, 20);
  return Buffer.concat([...locals, centralDir, end]);
}

function crc32(buffer) {
  let value = 0xffffffff;
  for (const byte of buffer) {
    value = (value >>> 8) ^ crcTable()[(value ^ byte) & 0xff];
  }
  return (value ^ 0xffffffff) >>> 0;
}

let cachedCrcTable = null;
function crcTable() {
  if (cachedCrcTable) return cachedCrcTable;
  cachedCrcTable = Array.from({ length: 256 }, (_unused, index) => {
    let value = index;
    for (let bit = 0; bit < 8; bit += 1) {
      value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
    }
    return value >>> 0;
  });
  return cachedCrcTable;
}

function tinyDocxBuffer(text) {
  return tinyZipBuffer({
    "word/document.xml": `<?xml version="1.0" encoding="UTF-8"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:body><w:p><w:r><w:t>${xmlEscape(text)}</w:t></w:r></w:p></w:body>
</w:document>`,
  }, { deflate: true });
}

function tinyXlsxBuffer(rows) {
  const shared = rows.flat().map((value) => `<si><t>${xmlEscape(value)}</t></si>`).join("");
  let index = 0;
  const rowXml = rows.map((row, rowIndex) => `<row r="${rowIndex + 1}">${
    row.map((_value, columnIndex) => `<c r="${String.fromCharCode(65 + columnIndex)}${rowIndex + 1}" t="s"><v>${index++}</v></c>`).join("")
  }</row>`).join("");
  return tinyZipBuffer({
    "xl/sharedStrings.xml": `<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">${shared}</sst>`,
    "xl/worksheets/sheet1.xml": `<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"><sheetData>${rowXml}</sheetData></worksheet>`,
  });
}

function tinyPptxBuffer(text) {
  return tinyZipBuffer({
    "ppt/slides/slide1.xml": `<?xml version="1.0" encoding="UTF-8"?>
<p:sld xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main">
  <p:cSld><p:spTree><p:sp><p:txBody><a:p><a:r><a:t>${xmlEscape(text)}</a:t></a:r></a:p></p:txBody></p:sp></p:spTree></p:cSld>
</p:sld>`,
  });
}

function xmlEscape(value) {
  return String(value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

test("POST /v1/responses maps to /v1/chat/completions and stores previous response replay", async () => {
  await withMockProvider(async (_req, res) => {
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_mock",
      object: "chat.completion",
      created: 100,
      model: "mock-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "hello from chat" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 3, completion_tokens: 4, total_tokens: 7 },
    }));
  }, async ({ bridgeAddress, requests }) => {
    const response = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        instructions: "short",
        input: "say hi",
        stop: ["<END>"],
        store: true,
      }),
    });
    assert.equal(response.status, 200);
    const json = await response.json();
    assert.equal(json.output[0].content[0].text, "hello from chat");
    assert.equal(requests[0].req.url, "/chat/completions");
    assert.deepEqual(requests[0].body.stop, ["<END>"]);
    assert.deepEqual(requests[0].body.messages.slice(0, 2), [
      { role: "system", content: "short" },
      { role: "user", content: "say hi" },
    ]);

    await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        previous_response_id: json.id,
        input: "continue",
      }),
    });
    assert.equal(requests[1].body.messages.at(-2).content, "hello from chat");
    assert.equal(requests[1].body.messages.at(-1).content, "continue");
  });
});

test("POST /v1/responses expands configured local prompt templates", async () => {
  await withMockProvider(async (_req, res, call) => {
    assert.deepEqual(call.body.messages, [
      { role: "system", content: "Use a terse style." },
      { role: "user", content: "Return exactly prompt-template-ok." },
      { role: "system", content: "Prefer exact output." },
      { role: "user", content: "Follow the reusable prompt." },
    ]);
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_prompt_template",
      object: "chat.completion",
      created: 100,
      model: "mock-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "prompt-template-ok" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 11, completion_tokens: 2, total_tokens: 13 },
    }));
  }, async ({ bridgeAddress }) => {
    const response = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        prompt: {
          id: "pmpt_test",
          version: "2",
          variables: {
            tone: "terse",
            answer: "prompt-template-ok",
          },
        },
        instructions: "Prefer exact output.",
        input: "Follow the reusable prompt.",
      }),
    });
    assert.equal(response.status, 200);
    const json = await response.json();
    assert.equal(json.output[0].content[0].text, "prompt-template-ok");
    assert.deepEqual(json.metadata.compatibility.prompt_template, {
      status: "expanded_locally",
      id: "pmpt_test",
      version: "2",
      variable_keys: ["tone", "answer"],
      message_count: 2,
      source: "configured_template",
    });
  }, {
    localPromptTemplates: {
      "pmpt_test@2": {
        instructions: "Use a {{tone}} style.",
        messages: [{ role: "user", content: "Return exactly {{answer}}." }],
      },
    },
  });
});

test("POST /v1/responses validates prompt references before provider calls", async () => {
  await withMockProvider(async () => {
    assert.fail("provider should not be called for invalid prompt references");
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const invalidCases = [
      {
        prompt: 42,
        param: "prompt",
        message: "prompt must be an object",
      },
      {
        prompt: [],
        param: "prompt",
        message: "prompt must be an object",
      },
      {
        prompt: {},
        param: "prompt.id",
        message: "prompt.id is required",
      },
      {
        prompt: { id: 123 },
        param: "prompt.id",
        message: "prompt.id must be a non-empty string",
      },
      {
        prompt: { id: null },
        param: "prompt.id",
        message: "prompt.id must be a non-empty string",
      },
      {
        prompt: { id: "" },
        param: "prompt.id",
        message: "prompt.id must be a non-empty string",
      },
      {
        prompt: { prompt_id: "" },
        param: "prompt.prompt_id",
        message: "prompt.prompt_id must be a non-empty string",
      },
      {
        prompt: { id: "pmpt_test", version: 2 },
        param: "prompt.version",
        message: "prompt.version must be a string",
      },
      {
        prompt: { id: "pmpt_test", variables: [] },
        param: "prompt.variables",
        message: "prompt.variables must be an object",
      },
      {
        prompt: { id: "pmpt_test", variables: { answer: 7 } },
        param: "prompt.variables.answer",
        message: "prompt.variables.answer must be a string or response input object",
      },
      {
        prompt: { id: "pmpt_test", variables: { answer: { type: "input_text" } } },
        param: "prompt.variables.answer.text",
        message: "prompt.variables.answer.text must be a string",
      },
      {
        prompt: { id: "pmpt_test", variables: { image: { type: "image_url", image_url: "https://example.test/a.png" } } },
        param: "prompt.variables.image.type",
        message: "prompt.variables.image.type must be one of: input_text, input_image, input_file",
      },
      {
        prompt: { id: "pmpt_test", variables: { file: { type: "input_file", file_id: 123 } } },
        param: "prompt.variables.file.file_id",
        message: "prompt.variables.file.file_id must be a string",
      },
      {
        prompt: { id: "pmpt_test", variables: { file: { type: "input_file", file_id: "file_test", detail: "auto" } } },
        param: "prompt.variables.file.detail",
        message: "prompt.variables.file.detail must be one of: low, high",
      },
    ];

    for (const invalidCase of invalidCases) {
      const response = await fetch(`${baseUrl}/v1/responses`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          model: "mock-model",
          input: "Validate prompt reference.",
          prompt: invalidCase.prompt,
        }),
      });
      assert.equal(response.status, 400, invalidCase.param);
      assert.deepEqual(await response.json(), {
        error: {
          message: invalidCase.message,
          type: "invalid_request_error",
          param: invalidCase.param,
          code: "invalid_request_parameter",
        },
      });
    }
    assert.equal(requests.length, 0);
  });
});

