test("POST /v1/responses maps output logprobs include to Chat and back", async () => {
  await withMockProvider(async (_req, res, call) => {
    assert.equal(call.body.logprobs, true);
    assert.equal(call.body.top_logprobs, 2);
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_logprobs",
      object: "chat.completion",
      created: 100,
      model: "mock-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "yes" },
        logprobs: {
          content: [{
            token: "yes",
            logprob: -0.02,
            bytes: [121, 101, 115],
            top_logprobs: [
              { token: "yes", logprob: -0.02, bytes: [121, 101, 115] },
              { token: "no", logprob: -4.5, bytes: [110, 111] },
            ],
          }],
        },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 3, completion_tokens: 1, total_tokens: 4 },
    }));
  }, async ({ bridgeAddress }) => {
    const response = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        input: "Answer yes.",
        include: ["message.output_text.logprobs"],
        top_logprobs: 2,
        store: true,
      }),
    });

    assert.equal(response.status, 200);
    const json = await response.json();
    const part = json.output[0].content[0];
    assert.equal(part.text, "yes");
    assert.equal(part.logprobs[0].token, "yes");
    assert.equal(part.logprobs[0].top_logprobs[1].token, "no");
    assert.equal(json.top_logprobs, 2);
    assert.equal(json.metadata.compatibility.logprobs, "chat_logprobs");

    const hiddenStoredResponse = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}`);
    assert.equal(hiddenStoredResponse.status, 200);
    const hiddenStoredJson = await hiddenStoredResponse.json();
    assert.equal(hiddenStoredJson.output[0].content[0].text, "yes");
    assert.equal(hiddenStoredJson.output[0].content[0].logprobs, undefined);

    const includedStoredResponse = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}?include[]=message.output_text.logprobs`);
    assert.equal(includedStoredResponse.status, 200);
    const includedStoredJson = await includedStoredResponse.json();
    assert.equal(includedStoredJson.output[0].content[0].text, "yes");
    assert.equal(includedStoredJson.output[0].content[0].logprobs[0].token, "yes");
    assert.equal(includedStoredJson.output[0].content[0].logprobs[0].top_logprobs[1].token, "no");

    const updatedHiddenResponse = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: { suite: "logprobs-update-hidden" } }),
    });
    assert.equal(updatedHiddenResponse.status, 200);
    const updatedHiddenJson = await updatedHiddenResponse.json();
    assert.equal(updatedHiddenJson.metadata.suite, "logprobs-update-hidden");
    assert.equal(updatedHiddenJson.output[0].content[0].text, "yes");
    assert.equal(updatedHiddenJson.output[0].content[0].logprobs, undefined);

    const updatedIncludedResponse = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}?include[]=message.output_text.logprobs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: { suite: "logprobs-update-included" } }),
    });
    assert.equal(updatedIncludedResponse.status, 200);
    const updatedIncludedJson = await updatedIncludedResponse.json();
    assert.equal(updatedIncludedJson.metadata.suite, "logprobs-update-included");
    assert.equal(updatedIncludedJson.output[0].content[0].logprobs[0].token, "yes");

    const invalidUpdateInclude = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}?include=not.a.real.include`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: { suite: "logprobs-update-invalid-include" } }),
    });
    assert.equal(invalidUpdateInclude.status, 400);
    assert.equal((await invalidUpdateInclude.json()).error.param, "include.0");

    const cancelledHiddenResponse = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}/cancel`, { method: "POST" });
    assert.equal(cancelledHiddenResponse.status, 200);
    const cancelledHiddenJson = await cancelledHiddenResponse.json();
    assert.match(cancelledHiddenJson.metadata.compatibility_cancel, /terminal responses/);
    assert.equal(cancelledHiddenJson.output[0].content[0].text, "yes");
    assert.equal(cancelledHiddenJson.output[0].content[0].logprobs, undefined);

    const cancelledIncludedResponse = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}/cancel?include[]=message.output_text.logprobs`, { method: "POST" });
    assert.equal(cancelledIncludedResponse.status, 200);
    const cancelledIncludedJson = await cancelledIncludedResponse.json();
    assert.equal(cancelledIncludedJson.output[0].content[0].logprobs[0].token, "yes");

    const invalidCancelInclude = await fetch(`http://127.0.0.1:${bridgeAddress.port}/v1/responses/${json.id}/cancel?include=not.a.real.include`, { method: "POST" });
    assert.equal(invalidCancelInclude.status, 400);
    assert.equal((await invalidCancelInclude.json()).error.param, "include.0");
  });
});

