test("local Conversations API persists items and feeds Responses conversation context", async () => {
  await withMockProvider(async (_req, res, call) => {
    assert.equal(call.body.messages[0].content, "Remember codeword delta-42.");
    assert.equal(call.body.messages.at(-1).content, "What codeword is stored?");
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_conversation",
      object: "chat.completion",
      created: 100,
      model: "mock-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "delta-42" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 6, completion_tokens: 2, total_tokens: 8 },
    }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const created = await fetch(`${baseUrl}/v1/conversations`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        metadata: { topic: "conversation-test" },
        items: [{
          type: "message",
          role: "user",
          content: "Remember codeword delta-42.",
        }],
      }),
    });
    assert.equal(created.status, 200);
    const createdJson = await created.json();
    assert.match(createdJson.id, /^conv_/);
    assert.equal(createdJson.object, "conversation");
    assert.deepEqual(createdJson.metadata, { topic: "conversation-test" });

    const updated = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: { topic: "updated" } }),
    });
    assert.equal(updated.status, 200);
    assert.deepEqual((await updated.json()).metadata, { topic: "updated" });

    const itemCreate = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        type: "message",
        role: "system",
        content: "Answer tersely.",
      }),
    });
    assert.equal(itemCreate.status, 200);
    const itemCreateJson = await itemCreate.json();
    assert.equal(itemCreateJson.type, "message");
    assert.equal(itemCreateJson.role, "system");

    const itemDelete = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items/${itemCreateJson.id}`, {
      method: "DELETE",
    });
    assert.equal(itemDelete.status, 200);
    const itemDeleteJson = await itemDelete.json();
    assert.equal(itemDeleteJson.id, createdJson.id);
    assert.equal(itemDeleteJson.object, "conversation");
    assert.deepEqual(itemDeleteJson.metadata, { topic: "updated" });

    const response = await fetch(`${baseUrl}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        conversation: createdJson.id,
        input: "What codeword is stored?",
        store: false,
      }),
    });
    assert.equal(response.status, 200);
    const responseJson = await response.json();
    assert.equal(responseJson.conversation, createdJson.id);
    assert.equal(responseJson.store, false);
    assert.equal(responseJson.output[0].content[0].text, "delta-42");
    assert.equal(responseJson.metadata.compatibility.local_conversation.id, createdJson.id);
    assert.equal(requests.length, 1);

    const items = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items?limit=2`);
    assert.equal(items.status, 200);
    const itemsJson = await items.json();
    assert.equal(itemsJson.object, "list");
    assert.equal(itemsJson.data.length, 2);
    assert.equal(itemsJson.has_more, true);

    const allItems = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items?order=asc`);
    assert.equal(allItems.status, 200);
    const allItemsJson = await allItems.json();
    assert.equal(allItemsJson.data.length, 3);
    assert.equal(allItemsJson.data[0].content, "Remember codeword delta-42.");
    assert.equal(allItemsJson.data[1].content[0].text, "What codeword is stored?");
    assert.equal(allItemsJson.data[2].role, "assistant");
    assert.equal(allItemsJson.data[2].content[0].text, "delta-42");

    const defaultItems = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items`);
    assert.equal(defaultItems.status, 200);
    const defaultItemsJson = await defaultItems.json();
    assert.equal(defaultItemsJson.data.length, 3);
    assert.equal(defaultItemsJson.data[0].id, allItemsJson.data[2].id);
    assert.equal(defaultItemsJson.data[2].id, allItemsJson.data[0].id);

    const retrievedItem = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items/${allItemsJson.data[2].id}`);
    assert.equal(retrievedItem.status, 200);
    assert.equal((await retrievedItem.json()).role, "assistant");

    const deletedConversation = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}`, { method: "DELETE" });
    assert.equal(deletedConversation.status, 200);
    assert.deepEqual(await deletedConversation.json(), {
      id: createdJson.id,
      object: "conversation.deleted",
      deleted: true,
    });

    const missing = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}`);
    assert.equal(missing.status, 404);

    const retainedItems = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items?order=asc`);
    assert.equal(retainedItems.status, 200);
    const retainedItemsJson = await retainedItems.json();
    assert.equal(retainedItemsJson.data.length, 3);
    assert.equal(retainedItemsJson.data[0].content, "Remember codeword delta-42.");
    assert.equal(retainedItemsJson.data[1].content[0].text, "What codeword is stored?");
    assert.equal(retainedItemsJson.data[2].content[0].text, "delta-42");

    const retainedItem = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items/${allItemsJson.data[0].id}`);
    assert.equal(retainedItem.status, 200);
    assert.equal((await retainedItem.json()).content, "Remember codeword delta-42.");

    const appendDeletedConversation = await fetch(`${baseUrl}/v1/conversations/${createdJson.id}/items`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ items: [{ type: "message", role: "user", content: "after delete" }] }),
    });
    assert.equal(appendDeletedConversation.status, 404);

    const replayDeletedConversation = await fetch(`${baseUrl}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        conversation: createdJson.id,
        input: "This should not replay.",
      }),
    });
    assert.equal(replayDeletedConversation.status, 404);
    const replayDeletedConversationJson = await replayDeletedConversation.json();
    assert.equal(replayDeletedConversationJson.error.code, "conversation_not_found");
    assert.equal(replayDeletedConversationJson.error.param, "conversation");
    assert.equal(requests.length, 1);
  });
});

test("local Conversations API validates metadata and request contracts", async () => {
  await withMockProvider(async () => {
    assert.fail("provider should not be called for local conversation validation");
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const createCases = [
      {
        name: "body-shape",
        body: [],
        message: "conversation request body must be a JSON object",
        param: null,
      },
      {
        name: "metadata-value-type",
        body: { metadata: { topic: "demo", owner: 7 } },
        message: "metadata values must be strings",
        param: "metadata.owner",
      },
      {
        name: "items-shape",
        body: { items: { type: "message", role: "user", content: "hello" } },
        message: "items must be an array or null",
        param: "items",
      },
      {
        name: "items-max",
        body: {
          items: Array.from({ length: 21 }, (_, index) => ({
            type: "message",
            role: "user",
            content: `item ${index}`,
          })),
        },
        message: "items must contain at most 20 items",
        param: "items",
      },
    ];

    for (const testCase of createCases) {
      const response = await fetch(`${baseUrl}/v1/conversations`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(testCase.body),
      });
      assert.equal(response.status, 400, testCase.name);
      const json = await response.json();
      assert.equal(json.error.message, testCase.message, testCase.name);
      assert.equal(json.error.param, testCase.param, testCase.name);
    }

    const created = await fetch(`${baseUrl}/v1/conversations`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: null, items: null }),
    });
    assert.equal(created.status, 200);
    const conversation = await created.json();
    assert.match(conversation.id, /^conv_/);
    assert.deepEqual(conversation.metadata, {});

    const itemCreateCases = [
      {
        name: "item-create-body-shape",
        body: [],
        message: "conversation items request body must be a JSON object",
        param: null,
      },
      {
        name: "item-create-missing-items",
        body: { metadata: { topic: "demo" } },
        message: "items is required",
        param: "items",
      },
      {
        name: "item-create-items-null",
        body: { items: null },
        message: "items must be an array",
        param: "items",
      },
      {
        name: "item-create-items-shape",
        body: { items: { type: "message", role: "user", content: "hello" } },
        message: "items must be an array",
        param: "items",
      },
      {
        name: "item-create-items-max",
        body: {
          items: Array.from({ length: 21 }, (_, index) => ({
            type: "message",
            role: "user",
            content: `item ${index}`,
          })),
        },
        message: "items must contain at most 20 items",
        param: "items",
      },
      {
        name: "item-create-local-item-extension-shape",
        body: { item: [{ type: "message", role: "user", content: "hello" }] },
        message: "item must be a conversation item object or string",
        param: "item",
      },
    ];

    for (const testCase of itemCreateCases) {
      const response = await fetch(`${baseUrl}/v1/conversations/${conversation.id}/items`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(testCase.body),
      });
      assert.equal(response.status, 400, testCase.name);
      const json = await response.json();
      assert.equal(json.error.message, testCase.message, testCase.name);
      assert.equal(json.error.param, testCase.param, testCase.name);
    }

    const officialItems = await fetch(`${baseUrl}/v1/conversations/${conversation.id}/items`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        items: [
          { type: "message", role: "user", content: "official item 1" },
          { type: "message", role: "user", content: "official item 2" },
        ],
      }),
    });
    assert.equal(officialItems.status, 200);
    const officialItemsJson = await officialItems.json();
    assert.equal(officialItemsJson.object, "list");
    assert.equal(officialItemsJson.data.length, 2);
    assert.equal(officialItemsJson.data[0].content, "official item 1");

    const localItemExtension = await fetch(`${baseUrl}/v1/conversations/${conversation.id}/items`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ item: "legacy item extension" }),
    });
    assert.equal(localItemExtension.status, 200);
    const localItemExtensionJson = await localItemExtension.json();
    assert.equal(localItemExtensionJson.type, "message");
    assert.equal(localItemExtensionJson.role, "user");
    assert.equal(localItemExtensionJson.content, "legacy item extension");

    const invalidIncludeCases = [
      {
        name: "item-create-invalid-include",
        method: "POST",
        path: `/v1/conversations/${conversation.id}/items?include=not.a.real.include`,
        body: { items: [{ type: "message", role: "user", content: "invalid include create" }] },
      },
      {
        name: "item-list-invalid-include",
        method: "GET",
        path: `/v1/conversations/${conversation.id}/items?include[]=not.a.real.include`,
      },
      {
        name: "item-get-invalid-include",
        method: "GET",
        path: `/v1/conversations/${conversation.id}/items/${officialItemsJson.data[0].id}?include=not.a.real.include`,
      },
    ];

    for (const testCase of invalidIncludeCases) {
      const response = await fetch(`${baseUrl}${testCase.path}`, {
        method: testCase.method,
        headers: testCase.body ? { "content-type": "application/json" } : undefined,
        body: testCase.body ? JSON.stringify(testCase.body) : undefined,
      });
      assert.equal(response.status, 400, testCase.name);
      const json = await response.json();
      assert.match(json.error.message, /^include\.0 must be one of:/, testCase.name);
      assert.equal(json.error.param, "include.0", testCase.name);
    }

    const invalidListOrder = await fetch(`${baseUrl}/v1/conversations/${conversation.id}/items?order=sideways`);
    assert.equal(invalidListOrder.status, 400);
    assert.deepEqual(await invalidListOrder.json(), {
      error: {
        message: "order must be one of: asc, desc",
        type: "invalid_request_error",
        param: "order",
        code: "invalid_request_parameter",
      },
    });

    for (const invalidLimit of ["abc", "1.5", "0", "101"]) {
      const invalidListLimit = await fetch(`${baseUrl}/v1/conversations/${conversation.id}/items?limit=${encodeURIComponent(invalidLimit)}`);
      assert.equal(invalidListLimit.status, 400);
      assert.deepEqual(await invalidListLimit.json(), {
        error: {
          message: "limit must be an integer between 1 and 100",
          type: "invalid_request_error",
          param: "limit",
          code: "invalid_request_parameter",
        },
      });
    }

    const updateCases = [
      {
        name: "update-body-shape",
        body: [],
        message: "conversation update body must be a JSON object",
        param: null,
      },
      {
        name: "update-missing-metadata",
        body: {},
        message: "metadata is required",
        param: "metadata",
      },
      {
        name: "update-metadata-value-type",
        body: { metadata: { topic: "demo", owner: 7 } },
        message: "metadata values must be strings",
        param: "metadata.owner",
      },
      {
        name: "update-unsupported-field",
        body: { metadata: { topic: "demo" }, items: [] },
        message: "only metadata updates are supported for conversations",
        param: "items",
      },
    ];

    for (const testCase of updateCases) {
      const response = await fetch(`${baseUrl}/v1/conversations/${conversation.id}`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify(testCase.body),
      });
      assert.equal(response.status, 400, testCase.name);
      const json = await response.json();
      assert.equal(json.error.message, testCase.message, testCase.name);
      assert.equal(json.error.param, testCase.param, testCase.name);
    }

    const updated = await fetch(`${baseUrl}/v1/conversations/${conversation.id}`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: { topic: "validated" } }),
    });
    assert.equal(updated.status, 200);
    assert.deepEqual((await updated.json()).metadata, { topic: "validated" });

    const cleared = await fetch(`${baseUrl}/v1/conversations/${conversation.id}`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: null }),
    });
    assert.equal(cleared.status, 200);
    assert.deepEqual((await cleared.json()).metadata, {});

    const refetched = await fetch(`${baseUrl}/v1/conversations/${conversation.id}`);
    assert.equal(refetched.status, 200);
    assert.deepEqual((await refetched.json()).metadata, {});
    assert.equal(requests.length, 0);
  });
});

test("Responses truncation auto drops oldest replay messages before upstream Chat", async () => {
  await withMockProvider(async (_req, res, call) => {
    const prompt = call.body.messages.map((message) => message.content || "").join("\n");
    assert.doesNotMatch(prompt, /drop-me-old-1/);
    assert.doesNotMatch(prompt, /drop-me-old-2/);
    assert.match(prompt, /keep-me-new/);
    assert.match(prompt, /truncation-current/);
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_truncation_auto",
      object: "chat.completion",
      created: 100,
      model: "mock-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "truncation-auto-ok" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 9, completion_tokens: 3, total_tokens: 12 },
    }));
  }, async ({ bridgeAddress }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const conversationResponse = await fetch(`${baseUrl}/v1/conversations`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        items: [
          { type: "message", role: "user", content: `drop-me-old-1 ${"x".repeat(240)}` },
          { type: "message", role: "assistant", content: `drop-me-old-2 ${"y".repeat(240)}` },
          { type: "message", role: "user", content: "keep-me-new" },
        ],
      }),
    });
    assert.equal(conversationResponse.status, 200);
    const conversation = await conversationResponse.json();

    const response = await fetch(`${baseUrl}/v1/responses`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        conversation: conversation.id,
        input: "truncation-current",
        truncation: "auto",
        store: false,
      }),
    });
    assert.equal(response.status, 200);
    const json = await response.json();
    assert.equal(json.output[0].content[0].text, "truncation-auto-ok");
    assert.equal(json.truncation, "auto");
    assert.equal(json.metadata.compatibility.local_truncation.status, "applied");
    assert.equal(json.metadata.compatibility.local_truncation.strategy, "auto");
    assert.equal(json.metadata.compatibility.local_truncation.max_input_chars, 260);
    assert.equal(json.metadata.compatibility.local_truncation.dropped_message_count, 2);
    assert.equal(json.metadata.compatibility.local_truncation.dropped_roles.user, 1);
    assert.equal(json.metadata.compatibility.local_truncation.dropped_roles.assistant, 1);
    assert.equal(json.metadata.compatibility.local_truncation.preserved_current_input, true);
    assert.ok(json.metadata.compatibility.local_truncation.estimated_chars_before > 260);
    assert.ok(json.metadata.compatibility.local_truncation.estimated_chars_after <= 260);
  }, { truncationMaxInputChars: 260 });
});

