test("POST /v1/chat/completions extracts direct Chat file content for text providers", async () => {
  const inlineBase64 = Buffer.from("Inline direct Chat file says chat-inline-file-ok.", "utf8").toString("base64");
  let localFileId = "";
  await withMockProvider(async (_req, res, call) => {
    assert.equal(call.body.store, true);
    assert.deepEqual(call.body.thinking, { type: "disabled" });
    assert.deepEqual(call.body.messages.map((message) => message.role), ["user", "system"]);
    assert.equal(typeof call.body.messages[0].content, "string");
    assert.match(call.body.messages[0].content, /Use direct Chat file context\./);
    assert.match(call.body.messages[0].content, new RegExp(`\\[file:${localFileId}\\]`));
    assert.match(call.body.messages[0].content, /\[file:inline-chat-file\.txt\]/);
    assert.doesNotMatch(call.body.messages[0].content, new RegExp(inlineBase64));
    assert.doesNotMatch(call.body.messages[0].content, /data:text\/plain/);
    assert.match(call.body.messages[1].content, /Local Responses input_file compatibility extracted file inputs follow/);
    assert.match(call.body.messages[1].content, /File ID direct Chat fixture says chat-file-id-ok\./);
    assert.match(call.body.messages[1].content, /Inline direct Chat file says chat-inline-file-ok\./);
    assert.doesNotMatch(call.body.messages[1].content, new RegExp(inlineBase64));

    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_direct_file_text_fallback",
      object: "chat.completion",
      created: 1700000413,
      model: "mock-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "chat-file-id-ok chat-inline-file-ok" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 18, completion_tokens: 6, total_tokens: 24 },
    }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const createdFile = await fetch(`${baseUrl}/v1/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        filename: "direct-chat-file.txt",
        purpose: "user_data",
        content: "File ID direct Chat fixture says chat-file-id-ok.",
      }),
    });
    assert.equal(createdFile.status, 200);
    const file = await createdFile.json();
    localFileId = file.id;

    const response = await fetch(`${baseUrl}/v1/chat/completions`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        store: true,
        metadata: { suite: "direct-chat-file-fallback" },
        messages: [{
          role: "user",
          content: [
            { type: "text", text: "Use direct Chat file context." },
            { type: "input_file", file_id: file.id },
            {
              type: "file",
              file: {
                filename: "inline-chat-file.txt",
                file_data: `data:text/plain;base64,${inlineBase64}`,
                mime_type: "text/plain",
              },
            },
          ],
        }],
      }),
    });
    assert.equal(response.status, 200);
    const json = await response.json();
    assert.equal(json.choices[0].message.content, "chat-file-id-ok chat-inline-file-ok");
    assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.provider, "text_fallback");
    assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.mode, "text");
    assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.file_part_count, 2);
    assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.file_id_count, 1);
    assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.inline_file_count, 1);
    assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.resolved_count, 2);
    assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.failed_count, 0);
    assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.deepseek_thinking, "disabled_for_input_files");
    assert.equal(requests.length, 1);

    const messages = await fetch(`${baseUrl}/v1/chat/completions/${json.id}/messages?limit=10`);
    assert.equal(messages.status, 200);
    const inputMessage = (await messages.json()).data.find((message) => message.direction === "input");
    assert.deepEqual(inputMessage.content.map((part) => part.type), ["text", "input_file", "file"]);
    assert.equal(inputMessage.name, null);
    assert.equal(inputMessage.content_parts, null);
  }, { chatFileInputMode: "text" });
});

test("POST /v1/chat/completions OCRs direct Chat PDF file content for text providers", async () => {
  await withTemporaryExecutableBin({
    pdftotext: [
      "#!/bin/sh",
      "exit 0",
      "",
    ].join("\n"),
    pdftoppm: [
      "#!/bin/sh",
      "prefix=\"\"",
      "for arg do prefix=\"$arg\"; done",
      "printf 'fake png bytes' > \"${prefix}-1.png\"",
      "exit 0",
      "",
    ].join("\n"),
    tesseract: [
      "#!/bin/sh",
      "printf 'Direct Chat OCR says chat-scanned-pdf-ok.\\n'",
      "exit 0",
      "",
    ].join("\n"),
  }, async () => {
    const inlinePdf = tinyPdfBuffer("").toString("base64");
    await withMockProvider(async (_req, res, call) => {
      assert.deepEqual(call.body.thinking, { type: "disabled" });
      assert.deepEqual(call.body.messages.map((message) => message.role), ["user", "system"]);
      assert.equal(typeof call.body.messages[0].content, "string");
      assert.match(call.body.messages[0].content, /Read direct Chat scanned PDF/);
      assert.match(call.body.messages[0].content, /\[file:inline-chat-scanned\.pdf\]/);
      assert.doesNotMatch(call.body.messages[0].content, new RegExp(inlinePdf));
      assert.doesNotMatch(call.body.messages[0].content, /data:application\/pdf/);
      assert.match(call.body.messages[1].content, /Local Responses input_file compatibility extracted file inputs follow/);
      assert.match(call.body.messages[1].content, /extraction_method: pdftoppm_tesseract_ocr/);
      assert.match(call.body.messages[1].content, /ocr_pages: 1/);
      assert.match(call.body.messages[1].content, /Page 1 OCR:/);
      assert.match(call.body.messages[1].content, /Direct Chat OCR says chat-scanned-pdf-ok/);
      assert.doesNotMatch(call.body.messages[1].content, /%PDF-1\.4/);

      res.writeHead(200, { "content-type": "application/json" });
      res.end(JSON.stringify({
        id: "chatcmpl_direct_file_pdf_ocr",
        object: "chat.completion",
        created: 1700000414,
        model: "mock-model",
        choices: [{
          index: 0,
          message: { role: "assistant", content: "chat-scanned-pdf-ok" },
          finish_reason: "stop",
        }],
        usage: { prompt_tokens: 20, completion_tokens: 4, total_tokens: 24 },
      }));
    }, async ({ bridgeAddress, requests }) => {
      const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
      const response = await fetch(`${baseUrl}/v1/chat/completions`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          model: "mock-model",
          store: true,
          metadata: { suite: "direct-chat-file-pdf-ocr" },
          messages: [{
            role: "user",
            content: [
              { type: "text", text: "Read direct Chat scanned PDF." },
              {
                type: "file",
                file: {
                  filename: "inline-chat-scanned.pdf",
                  file_data: `data:application/pdf;base64,${inlinePdf}`,
                  mime_type: "application/pdf",
                },
              },
            ],
          }],
        }),
      });
      assert.equal(response.status, 200);
      const json = await response.json();
      assert.equal(json.choices[0].message.content, "chat-scanned-pdf-ok");
      assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.provider, "text_fallback");
      assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.mode, "text");
      assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.file_part_count, 1);
      assert.equal(json.metadata.compatibility.chat_passthrough.chat_file_inputs.inline_file_count, 1);
      assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.resolved_count, 1);
      assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.failed_count, 0);
      assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.pdf_extracted_count, 1);
      assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.pdf_ocr_extracted_count, 1);
      assert.equal(json.metadata.compatibility.chat_passthrough.local_input_files.deepseek_thinking, "disabled_for_input_files");
      assert.equal(requests.length, 1);

      const messages = await fetch(`${baseUrl}/v1/chat/completions/${json.id}/messages?limit=10`);
      assert.equal(messages.status, 200);
      const inputMessage = (await messages.json()).data.find((message) => message.direction === "input");
      assert.deepEqual(inputMessage.content.map((part) => part.type), ["text", "file"]);
    }, {
      chatFileInputMode: "text",
      inputFilePdfOcr: "tesseract",
      inputFilePdfOcrMaxPages: 1,
      inputFilePdfOcrDpi: 72,
    });
  });
});

test("POST /v1/chat/completions streams with direct Chat image text fallback", async () => {
  await withMockProvider(async (_req, res, call) => {
    assert.equal(call.body.stream, true);
    assert.equal(typeof call.body.messages[0].content, "string");
    assert.match(call.body.messages[0].content, /\[image:https:\/\/example\.test\/chat-stream-vision\.png\]/);
    res.writeHead(200, { "content-type": "text/event-stream" });
    res.write(`data: ${JSON.stringify({
      id: "chatcmpl_direct_image_stream_fallback",
      object: "chat.completion.chunk",
      created: 1700000412,
      model: "mock-model",
      choices: [{ index: 0, delta: { role: "assistant", content: "chat-image-" }, finish_reason: null }],
    })}\n\n`);
    res.write(`data: ${JSON.stringify({
      id: "chatcmpl_direct_image_stream_fallback",
      object: "chat.completion.chunk",
      created: 1700000412,
      model: "mock-model",
      choices: [{ index: 0, delta: { content: "stream-ok" }, finish_reason: "stop" }],
      usage: { prompt_tokens: 11, completion_tokens: 4, total_tokens: 15 },
    })}\n\n`);
    res.write("data: [DONE]\n\n");
    res.end();
  }, async ({ bridgeAddress }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const response = await fetch(`${baseUrl}/v1/chat/completions`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        model: "mock-model",
        store: true,
        stream: true,
        messages: [{
          role: "user",
          content: [
            { type: "text", text: "Stream direct Chat image markers." },
            {
              type: "image_url",
              image_url: {
                url: "https://example.test/chat-stream-vision.png",
                detail: "auto",
              },
            },
          ],
        }],
      }),
    });
    assert.equal(response.status, 200);
    const events = parseSseEvents(await response.text());
    assert.equal(events.at(-1).data, "[DONE]");
    const completionId = events[0].data.id;
    assert.equal(events.slice(0, -1).map((event) => event.data.choices[0].delta.content || "").join(""), "chat-image-stream-ok");

    const fetched = await fetch(`${baseUrl}/v1/chat/completions/${completionId}`);
    assert.equal(fetched.status, 200);
    const fetchedJson = await fetched.json();
    assert.equal(fetchedJson.metadata.compatibility.chat_passthrough.chat_image_inputs.provider, "text_fallback");
    assert.equal(fetchedJson.metadata.compatibility.chat_passthrough.chat_image_inputs.image_part_count, 1);
  }, { chatImageInputMode: "text" });
});

