test("Evals API creates local runs and output items from eval JSONL", async () => {
  await withMockProvider(async (_req, res) => {
    res.writeHead(500, { "content-type": "application/json" });
    res.end(JSON.stringify({ error: { message: "provider should not be called for sample-driven evals" } }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;

    const createdEvalResponse = await fetch(`${baseUrl}/v1/evals`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        name: "Ticket label eval",
        data_source_config: {
          type: "custom",
          item_schema: {
            type: "object",
            properties: {
              ticket_text: { type: "string" },
              correct_label: { type: "string" },
            },
            required: ["ticket_text", "correct_label"],
          },
          include_sample_schema: true,
        },
        testing_criteria: [{
          type: "string_check",
          name: "Exact label match",
          input: "{{ sample.output_text }}",
          operation: "eq",
          reference: "{{ item.correct_label }}",
        }],
        metadata: { suite: "evals-local" },
      }),
    });
    assert.equal(createdEvalResponse.status, 201);
    const evalObject = await createdEvalResponse.json();
    assert.match(evalObject.id, /^eval_/);
    assert.equal(evalObject.object, "eval");
    assert.equal(evalObject.testing_criteria.length, 1);
    assert.match(evalObject.testing_criteria[0].id, /^Exact-label-match-/);

    const jsonl = [
      {
        item: { ticket_text: "My monitor will not turn on", correct_label: "Hardware" },
        sample: { output_text: "Hardware" },
      },
      {
        item: { ticket_text: "I cannot quit vim", correct_label: "Software" },
        sample: { output_text: "Hardware" },
      },
    ].map((line) => JSON.stringify(line)).join("\n") + "\n";

    const fileResponse = await fetch(`${baseUrl}/v1/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        filename: "eval-tickets.jsonl",
        purpose: "evals",
        content_base64: Buffer.from(jsonl, "utf8").toString("base64"),
        mime_type: "application/jsonl",
      }),
    });
    assert.equal(fileResponse.status, 200);
    const file = await fileResponse.json();

    const runResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        name: "sample labels",
        data_source: {
          type: "responses",
          model: "mock-model",
          source: { type: "file_id", id: file.id },
          input_messages: {
            type: "template",
            template: [
              { role: "developer", content: "Return one ticket label." },
              { role: "user", content: "{{ item.ticket_text }}" },
            ],
          },
        },
      }),
    });
    assert.equal(runResponse.status, 200);
    const run = await runResponse.json();
    assert.match(run.id, /^evalrun_/);
    assert.equal(run.object, "eval.run");
    assert.equal(run.status, "completed");
    assert.equal(run.result_counts.total, 2);
    assert.equal(run.result_counts.passed, 1);
    assert.equal(run.result_counts.failed, 1);
    assert.equal(run.result_counts.errored, 0);
    assert.equal(run.per_model_usage, null);
    assert.equal(run.per_testing_criteria_results[0].passed, 1);
    assert.equal(run.per_testing_criteria_results[0].failed, 1);
    assert.equal(requests.length, 0);

    const outputItemsResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs/${run.id}/output_items?limit=10`);
    assert.equal(outputItemsResponse.status, 200);
    const outputItems = await outputItemsResponse.json();
    assert.equal(outputItems.object, "list");
    assert.equal(outputItems.data.length, 2);
    assert.deepEqual(outputItems.data.map((item) => item.status), ["passed", "failed"]);
    assert.equal(outputItems.data[0].sample.output_text, "Hardware");
    assert.equal(outputItems.data[1].results[0].reference, "Software");

    const outputItemResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs/${run.id}/output_items/${outputItems.data[0].id}`);
    assert.equal(outputItemResponse.status, 200);
    const outputItem = await outputItemResponse.json();
    assert.equal(outputItem.id, outputItems.data[0].id);
    assert.equal(outputItem.datasource_item.item.correct_label, "Hardware");

    const runGet = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs/${run.id}`);
    assert.equal(runGet.status, 200);
    assert.equal((await runGet.json()).id, run.id);

    const runList = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs?limit=1`);
    assert.equal(runList.status, 200);
    assert.equal((await runList.json()).data[0].id, run.id);

    const updatedEvalResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ metadata: { suite: "evals-updated" } }),
    });
    assert.equal(updatedEvalResponse.status, 200);
    assert.deepEqual((await updatedEvalResponse.json()).metadata, { suite: "evals-updated" });

    const evalList = await fetch(`${baseUrl}/v1/evals?order=desc&order_by=updated_at`);
    assert.equal(evalList.status, 200);
    assert.equal((await evalList.json()).data[0].id, evalObject.id);

    const deleteEvalResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}`, { method: "DELETE" });
    assert.equal(deleteEvalResponse.status, 200);
    assert.deepEqual(await deleteEvalResponse.json(), {
      id: evalObject.id,
      object: "eval.deleted",
      deleted: true,
    });

    const missingEvalResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}`);
    assert.equal(missingEvalResponse.status, 404);
  });
});

test("Graders API validates and runs local text similarity, python, and multi graders", async () => {
  await withMockProvider(async (_req, res) => {
    res.writeHead(500, { "content-type": "application/json" });
    res.end(JSON.stringify({ error: { message: "provider should not be called for local graders" } }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;

    const validateResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/validate`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "string_check",
          name: "exact",
          input: "{{ sample.output_text }}",
          reference: "{{ item.label }}",
          operation: "eq",
        },
      }),
    });
    assert.equal(validateResponse.status, 200);
    assert.equal((await validateResponse.json()).grader.name, "exact");

    const similarityResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/run`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "text_similarity",
          name: "summary_similarity",
          input: "{{ sample.output_text }}",
          reference: "{{ item.reference_answer }}",
          evaluation_metric: "rouge_l",
          pass_threshold: 0.5,
        },
        item: { reference_answer: "The router was restarted successfully" },
        model_sample: "Router restarted successfully",
      }),
    });
    assert.equal(similarityResponse.status, 200);
    const similarity = await similarityResponse.json();
    assert.equal(similarity.metadata.type, "text_similarity");
    assert.equal(similarity.metadata.errors.other_error, false);
    assert.ok(similarity.reward >= 0.5);
    assert.deepEqual(similarity.model_grader_token_usage_per_model, {});

    const multiResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/run`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "multi",
          name: "contact_json",
          graders: {
            name: {
              type: "text_similarity",
              input: "{{ sample.output_json.name }}",
              reference: "{{ item.name }}",
              evaluation_metric: "fuzzy_match",
              pass_threshold: 0.7,
            },
            email: {
              type: "string_check",
              input: "{{ sample.output_json.email }}",
              reference: "{{ item.email }}",
              operation: "eq",
            },
          },
          calculate_output: "(name + email) / 2",
          pass_threshold: 0.8,
        },
        item: { name: "Jane Doe", email: "jane@example.com" },
        model_sample: {
          output_text: "{\"name\":\"Jane Do\",\"email\":\"jane@example.com\"}",
          output_json: { name: "Jane Do", email: "jane@example.com" },
        },
      }),
    });
    assert.equal(multiResponse.status, 200);
    const multi = await multiResponse.json();
    assert.equal(multi.metadata.type, "multi");
    assert.ok(multi.reward >= 0.8);
    assert.ok(multi.sub_rewards.name >= 0.7);
    assert.equal(multi.sub_rewards.email, 1);

    const pythonValidateResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/validate`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "python",
          source: "def grade(sample, item):\n    return 1.0",
        },
      }),
    });
    assert.equal(pythonValidateResponse.status, 200);
    assert.equal((await pythonValidateResponse.json()).grader.type, "python");

    const pythonRunResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/run`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "python",
          name: "length_ratio",
          source: [
            "def grade(sample, item):",
            "    output_text = sample.get('output_text', '')",
            "    expected = item.get('expected', '')",
            "    return 1.0 if output_text.strip() == expected else 0.25",
          ].join("\n"),
        },
        item: { expected: "deploy-ok" },
        model_sample: "deploy-ok",
      }),
    });
    assert.equal(pythonRunResponse.status, 200);
    const pythonRun = await pythonRunResponse.json();
    assert.equal(pythonRun.reward, 1);
    assert.equal(pythonRun.metadata.type, "python");
    assert.equal(pythonRun.metadata.errors.python_grader_runtime_error, false);
    assert.equal(pythonRun.metadata.errors.python_grader_server_error, false);
    assert.equal(pythonRun.metadata.compatibility.python_grader.image_tag, "2025-05-08");
    assert.equal(pythonRun.metadata.compatibility.python_grader.network, "blocked_by_local_runner");

    const pythonRuntimeErrorResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/run`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "python",
          name: "broken",
          source: "def grade(sample, item):\n    raise ValueError('bad sample')",
        },
        item: {},
        model_sample: "anything",
      }),
    });
    assert.equal(pythonRuntimeErrorResponse.status, 200);
    const pythonRuntimeError = await pythonRuntimeErrorResponse.json();
    assert.equal(pythonRuntimeError.reward, 0);
    assert.equal(pythonRuntimeError.metadata.errors.python_grader_runtime_error, true);
    assert.equal(pythonRuntimeError.metadata.errors.python_grader_server_error, false);
    assert.match(pythonRuntimeError.metadata.errors.python_grader_runtime_error_details, /ValueError|bad sample/);

    const unsupportedResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/validate`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "javascript",
          source: "function grade() { return 1 }",
        },
      }),
    });
    assert.equal(unsupportedResponse.status, 400);
    assert.equal((await unsupportedResponse.json()).error.code, "unsupported_grader_type");
    assert.equal(requests.length, 0);
  });
});

test("Graders API runs provider-backed score_model graders", async () => {
  await withMockProvider(async (_req, res, captured) => {
    assert.equal(captured.body.response_format.type, "json_object");
    assert.equal(captured.body.model, "judge-model");
    assert.equal(captured.body.temperature, 0);
    const rendered = JSON.stringify(captured.body.messages);
    assert.match(rendered, /Reference: green/);
    assert.match(rendered, /Model: greenish/);
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_judge",
      object: "chat.completion",
      created: 100,
      model: "judge-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "{\"result\":0.75,\"steps\":[]}" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 12, completion_tokens: 3, total_tokens: 15 },
    }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;

    const validateResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/validate`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "score_model",
          name: "semantic_judge",
          input: [{ role: "user", content: "Reference: {{ item.reference }}\nModel: {{ sample.output_text }}" }],
          model: "judge-model",
          range: [0, 1],
          pass_threshold: 0.7,
          sampling_params: { temperature: 0, max_completion_tokens: 32 },
        },
      }),
    });
    assert.equal(validateResponse.status, 200);
    assert.equal((await validateResponse.json()).grader.type, "score_model");
    assert.equal(requests.length, 0);

    const runResponse = await fetch(`${baseUrl}/v1/fine_tuning/alpha/graders/run`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        grader: {
          type: "score_model",
          name: "semantic_judge",
          input: [{ role: "user", content: "Reference: {{ item.reference }}\nModel: {{ sample.output_text }}" }],
          model: "judge-model",
          range: [0, 1],
          pass_threshold: 0.7,
          sampling_params: { temperature: 0, max_completion_tokens: 32 },
        },
        item: { reference: "green" },
        model_sample: "greenish",
      }),
    });
    assert.equal(runResponse.status, 200);
    const run = await runResponse.json();
    assert.equal(run.reward, 0.75);
    assert.equal(run.metadata.type, "score_model");
    assert.equal(run.metadata.sampled_model_name, "judge-model");
    assert.equal(run.metadata.errors.model_grader_parse_error, false);
    assert.equal(run.metadata.errors.model_grader_server_error, false);
    assert.deepEqual(run.metadata.token_usage, {
      prompt_tokens: 12,
      total_tokens: 15,
      completion_tokens: 3,
      cached_tokens: 0,
    });
    assert.deepEqual(run.model_grader_token_usage_per_model["judge-model"], run.metadata.token_usage);
    assert.equal(requests.length, 1);
  });
});

test("Evals API runs local text similarity, python, and multi graders", async () => {
  await withMockProvider(async (_req, res) => {
    res.writeHead(500, { "content-type": "application/json" });
    res.end(JSON.stringify({ error: { message: "provider should not be called for sample-driven evals" } }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;

    const createdEvalResponse = await fetch(`${baseUrl}/v1/evals`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        name: "Summary quality eval",
        data_source_config: {
          type: "custom",
          include_sample_schema: true,
          item_schema: {
            type: "object",
            properties: {
              reference_answer: { type: "string" },
              name: { type: "string" },
              email: { type: "string" },
            },
          },
        },
        testing_criteria: [
          {
            type: "text_similarity",
            name: "Reference similarity",
            input: "{{ sample.output_text }}",
            reference: "{{ item.reference_answer }}",
            evaluation_metric: "rouge_l",
            pass_threshold: 0.5,
          },
          {
            type: "multi",
            name: "Contact JSON",
            graders: {
              name: {
                type: "text_similarity",
                input: "{{ sample.output_json.name }}",
                reference: "{{ item.name }}",
                evaluation_metric: "fuzzy_match",
                pass_threshold: 0.7,
              },
              email: {
                type: "string_check",
                input: "{{ sample.output_json.email }}",
                reference: "{{ item.email }}",
                operation: "eq",
              },
            },
            calculate_output: "(name + email) / 2",
            pass_threshold: 0.8,
          },
          {
            type: "python",
            name: "Python sample check",
            source: [
              "def grade(sample, item):",
              "    output_text = sample.get('output_text', '')",
              "    reference = item.get('reference_answer', '')",
              "    return 1.0 if 'router' in output_text.lower() and 'router' in reference.lower() else 0.0",
            ].join("\n"),
          },
        ],
      }),
    });
    assert.equal(createdEvalResponse.status, 201);
    const evalObject = await createdEvalResponse.json();

    const jsonl = JSON.stringify({
      item: {
        reference_answer: "The router was restarted successfully",
        name: "Jane Doe",
        email: "jane@example.com",
      },
      sample: {
        output_text: "Router restarted successfully",
        output_json: { name: "Jane Do", email: "jane@example.com" },
      },
    }) + "\n";
    const fileResponse = await fetch(`${baseUrl}/v1/files`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        filename: "eval-graders.jsonl",
        purpose: "evals",
        content_base64: Buffer.from(jsonl, "utf8").toString("base64"),
        mime_type: "application/jsonl",
      }),
    });
    assert.equal(fileResponse.status, 200);
    const file = await fileResponse.json();

    const runResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        data_source: {
          type: "responses",
          model: "mock-model",
          source: { type: "file_id", id: file.id },
          input_messages: {
            type: "template",
            template: [{ role: "user", content: "{{ item.reference_answer }}" }],
          },
        },
      }),
    });
    assert.equal(runResponse.status, 200);
    const run = await runResponse.json();
    assert.equal(run.status, "completed");
    assert.equal(run.result_counts.total, 1);
    assert.equal(run.result_counts.passed, 1);
    assert.deepEqual(run.metadata.compatibility.supported_graders, ["string_check", "text_similarity", "score_model", "python", "multi"]);
    assert.equal(run.per_testing_criteria_results.length, 3);
    assert.equal(run.per_testing_criteria_results.every((result) => result.passed === 1), true);

    const outputItemsResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs/${run.id}/output_items`);
    assert.equal(outputItemsResponse.status, 200);
    const outputItems = await outputItemsResponse.json();
    assert.equal(outputItems.data[0].status, "passed");
    assert.equal(outputItems.data[0].results[0].type, "text_similarity");
    assert.ok(outputItems.data[0].results[0].score >= 0.5);
    assert.equal(outputItems.data[0].results[1].type, "multi");
    assert.ok(outputItems.data[0].results[1].sub_rewards.email === 1);
    assert.equal(outputItems.data[0].results[2].type, "python");
    assert.equal(outputItems.data[0].results[2].score, 1);
    assert.equal(outputItems.data[0].results[2].python_grader_details.network, "blocked_by_local_runner");
    assert.equal(requests.length, 0);
  });
});

test("Evals API runs provider-backed score_model criteria", async () => {
  await withMockProvider(async (_req, res, captured) => {
    const prompt = JSON.stringify(captured.body.messages);
    assert.match(prompt, /Expected: deploy succeeded/);
    assert.match(prompt, /Actual: deploy succeeded with warning/);
    res.writeHead(200, { "content-type": "application/json" });
    res.end(JSON.stringify({
      id: "chatcmpl_eval_judge",
      object: "chat.completion",
      created: 100,
      model: "judge-model",
      choices: [{
        index: 0,
        message: { role: "assistant", content: "{\"result\":0.8,\"steps\":[{\"description\":\"semantic match\",\"conclusion\":\"close\"}]}" },
        finish_reason: "stop",
      }],
      usage: { prompt_tokens: 20, completion_tokens: 5, total_tokens: 25 },
    }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const createdEvalResponse = await fetch(`${baseUrl}/v1/evals`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        name: "Judge eval",
        data_source_config: { type: "custom", include_sample_schema: true },
        testing_criteria: [{
          type: "score_model",
          name: "judge",
          input: [{ role: "user", content: "Expected: {{ item.expected }}\nActual: {{ sample.output_text }}" }],
          model: "judge-model",
          range: [0, 1],
          pass_threshold: 0.7,
          sampling_params: { temperature: 0, max_completion_tokens: 32 },
        }],
      }),
    });
    assert.equal(createdEvalResponse.status, 201);
    const evalObject = await createdEvalResponse.json();

    const runResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({
        data_source: {
          type: "responses",
          model: "mock-model",
          source: {
            type: "custom",
            data: [{
              item: { expected: "deploy succeeded" },
              sample: { output_text: "deploy succeeded with warning" },
            }],
          },
          input_messages: [{ role: "user", content: "{{ item.expected }}" }],
        },
      }),
    });
    assert.equal(runResponse.status, 200);
    const run = await runResponse.json();
    assert.equal(run.status, "completed");
    assert.equal(run.result_counts.passed, 1);
    assert.deepEqual(run.per_model_usage, [{
      model_name: "judge-model",
      invocation_count: 1,
      prompt_tokens: 20,
      completion_tokens: 5,
      total_tokens: 25,
      cached_tokens: 0,
    }]);

    const outputItemsResponse = await fetch(`${baseUrl}/v1/evals/${evalObject.id}/runs/${run.id}/output_items`);
    assert.equal(outputItemsResponse.status, 200);
    const outputItems = await outputItemsResponse.json();
    assert.equal(outputItems.data[0].status, "passed");
    assert.equal(outputItems.data[0].results[0].type, "score_model");
    assert.equal(outputItems.data[0].results[0].score, 0.8);
    assert.equal(outputItems.data[0].results[0].sampled_model_name, "judge-model");
    assert.equal(requests.length, 1);
  });
});

test("GET /healthz does not require a provider key", async () => {
  const server = createServer(loadConfig({ providerApiKey: "", providerBaseUrl: "http://127.0.0.1:1" }));
  const address = await listen(server);
  try {
    const response = await fetch(`http://127.0.0.1:${address.port}/healthz`);
    const json = await response.json();
    assert.equal(json.ok, true);
    assert.equal(json.has_provider_key, false);
  } finally {
    await close(server);
  }
});

test("loadConfig filters provider-specific Chat fields for DeepSeek providers by default", () => {
  const previousServiceTier = process.env.CODEXCOMPAT_FORWARD_SERVICE_TIER;
  const previousStoredChatFields = process.env.CODEXCOMPAT_FORWARD_STORED_CHAT_FIELDS;
  const previousChatNativeFields = process.env.CODEXCOMPAT_FORWARD_CHAT_NATIVE_FIELDS;
  const previousChatCustomTools = process.env.CODEXCOMPAT_FORWARD_CHAT_CUSTOM_TOOLS;
  const previousStreamOptionFields = process.env.CODEXCOMPAT_STREAM_OPTION_FIELDS;
  const previousChatImageInputMode = process.env.CODEXCOMPAT_CHAT_IMAGE_INPUT_MODE;
  const previousChatAudioInputMode = process.env.CODEXCOMPAT_CHAT_AUDIO_INPUT_MODE;
  const previousChatFileInputMode = process.env.CODEXCOMPAT_CHAT_FILE_INPUT_MODE;
  const previousChatNEmulationMax = process.env.CODEXCOMPAT_CHAT_N_EMULATION_MAX;
  const previousUploadRetainPartData = process.env.CODEXCOMPAT_UPLOAD_RETAIN_PART_DATA;
  delete process.env.CODEXCOMPAT_FORWARD_SERVICE_TIER;
  delete process.env.CODEXCOMPAT_FORWARD_STORED_CHAT_FIELDS;
  delete process.env.CODEXCOMPAT_FORWARD_CHAT_NATIVE_FIELDS;
  delete process.env.CODEXCOMPAT_FORWARD_CHAT_CUSTOM_TOOLS;
  delete process.env.CODEXCOMPAT_STREAM_OPTION_FIELDS;
  delete process.env.CODEXCOMPAT_CHAT_IMAGE_INPUT_MODE;
  delete process.env.CODEXCOMPAT_CHAT_AUDIO_INPUT_MODE;
  delete process.env.CODEXCOMPAT_CHAT_FILE_INPUT_MODE;
  delete process.env.CODEXCOMPAT_CHAT_N_EMULATION_MAX;
  delete process.env.CODEXCOMPAT_UPLOAD_RETAIN_PART_DATA;
  try {
    const deepseekConfig = loadConfig({ providerBaseUrl: "https://api.deepseek.com" });
    assert.equal(deepseekConfig.forwardServiceTier, false);
    assert.equal(deepseekConfig.forwardStoredChatFields, false);
    assert.equal(deepseekConfig.forwardChatNativeFields, false);
    assert.equal(deepseekConfig.forwardChatCustomTools, false);
    assert.deepEqual(deepseekConfig.streamOptionFields, ["include_usage"]);
    assert.equal(deepseekConfig.chatImageInputMode, "text");
    assert.equal(deepseekConfig.chatAudioInputMode, "text");
    assert.equal(deepseekConfig.chatFileInputMode, "text");
    assert.equal(deepseekConfig.chatNEmulationMax, 10);
    assert.equal(deepseekConfig.uploadRetainPartData, false);
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com", uploadRetainPartData: true }).uploadRetainPartData, true);

    const openaiCompatibleConfig = loadConfig({ providerBaseUrl: "https://api.openai-compatible.test" });
    assert.equal(openaiCompatibleConfig.forwardServiceTier, true);
    assert.equal(openaiCompatibleConfig.forwardStoredChatFields, true);
    assert.equal(openaiCompatibleConfig.forwardChatNativeFields, true);
    assert.equal(openaiCompatibleConfig.forwardChatCustomTools, true);
    assert.equal(openaiCompatibleConfig.streamOptionFields, null);
    assert.equal(openaiCompatibleConfig.chatImageInputMode, "vision");
    assert.equal(openaiCompatibleConfig.chatAudioInputMode, "audio");
    assert.equal(openaiCompatibleConfig.chatFileInputMode, "file");

    process.env.CODEXCOMPAT_CHAT_IMAGE_INPUT_MODE = "vision";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).chatImageInputMode, "vision");

    process.env.CODEXCOMPAT_CHAT_IMAGE_INPUT_MODE = "text";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.openai-compatible.test" }).chatImageInputMode, "text");

    process.env.CODEXCOMPAT_CHAT_AUDIO_INPUT_MODE = "audio";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).chatAudioInputMode, "audio");

    process.env.CODEXCOMPAT_CHAT_AUDIO_INPUT_MODE = "text";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.openai-compatible.test" }).chatAudioInputMode, "text");

    process.env.CODEXCOMPAT_CHAT_FILE_INPUT_MODE = "file";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).chatFileInputMode, "file");

    process.env.CODEXCOMPAT_CHAT_FILE_INPUT_MODE = "text";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.openai-compatible.test" }).chatFileInputMode, "text");

    process.env.CODEXCOMPAT_CHAT_N_EMULATION_MAX = "3";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).chatNEmulationMax, 3);

    process.env.CODEXCOMPAT_STREAM_OPTION_FIELDS = "*";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).streamOptionFields, null);

    process.env.CODEXCOMPAT_STREAM_OPTION_FIELDS = "include_usage, provider_extra";
    assert.deepEqual(
      loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).streamOptionFields,
      ["include_usage", "provider_extra"],
    );

    process.env.CODEXCOMPAT_UPLOAD_RETAIN_PART_DATA = "true";
    assert.equal(loadConfig({ providerBaseUrl: "https://api.deepseek.com" }).uploadRetainPartData, true);
  } finally {
    if (previousServiceTier === undefined) delete process.env.CODEXCOMPAT_FORWARD_SERVICE_TIER;
    else process.env.CODEXCOMPAT_FORWARD_SERVICE_TIER = previousServiceTier;
    if (previousStoredChatFields === undefined) delete process.env.CODEXCOMPAT_FORWARD_STORED_CHAT_FIELDS;
    else process.env.CODEXCOMPAT_FORWARD_STORED_CHAT_FIELDS = previousStoredChatFields;
    if (previousChatNativeFields === undefined) delete process.env.CODEXCOMPAT_FORWARD_CHAT_NATIVE_FIELDS;
    else process.env.CODEXCOMPAT_FORWARD_CHAT_NATIVE_FIELDS = previousChatNativeFields;
    if (previousChatCustomTools === undefined) delete process.env.CODEXCOMPAT_FORWARD_CHAT_CUSTOM_TOOLS;
    else process.env.CODEXCOMPAT_FORWARD_CHAT_CUSTOM_TOOLS = previousChatCustomTools;
    if (previousStreamOptionFields === undefined) delete process.env.CODEXCOMPAT_STREAM_OPTION_FIELDS;
    else process.env.CODEXCOMPAT_STREAM_OPTION_FIELDS = previousStreamOptionFields;
    if (previousChatImageInputMode === undefined) delete process.env.CODEXCOMPAT_CHAT_IMAGE_INPUT_MODE;
    else process.env.CODEXCOMPAT_CHAT_IMAGE_INPUT_MODE = previousChatImageInputMode;
    if (previousChatAudioInputMode === undefined) delete process.env.CODEXCOMPAT_CHAT_AUDIO_INPUT_MODE;
    else process.env.CODEXCOMPAT_CHAT_AUDIO_INPUT_MODE = previousChatAudioInputMode;
    if (previousChatFileInputMode === undefined) delete process.env.CODEXCOMPAT_CHAT_FILE_INPUT_MODE;
    else process.env.CODEXCOMPAT_CHAT_FILE_INPUT_MODE = previousChatFileInputMode;
    if (previousChatNEmulationMax === undefined) delete process.env.CODEXCOMPAT_CHAT_N_EMULATION_MAX;
    else process.env.CODEXCOMPAT_CHAT_N_EMULATION_MAX = previousChatNEmulationMax;
    if (previousUploadRetainPartData === undefined) delete process.env.CODEXCOMPAT_UPLOAD_RETAIN_PART_DATA;
    else process.env.CODEXCOMPAT_UPLOAD_RETAIN_PART_DATA = previousUploadRetainPartData;
  }
});

test("loadConfig reads input_file PDF OCR settings", () => {
  const envNames = [
    "CODEXCOMPAT_INPUT_FILE_PDF_OCR",
    "CODEXCOMPAT_INPUT_FILE_PDF_OCR_MAX_PAGES",
    "CODEXCOMPAT_INPUT_FILE_PDF_OCR_DPI",
    "CODEXCOMPAT_INPUT_FILE_PDF_OCR_LANGUAGE",
  ];
  const previous = new Map(envNames.map((name) => [name, process.env[name]]));
  for (const name of envNames) delete process.env[name];
  try {
    const defaults = loadConfig({ providerBaseUrl: "https://api.deepseek.com" });
    assert.equal(defaults.inputFilePdfOcr, "auto");
    assert.equal(defaults.inputFilePdfOcrMaxPages, 3);
    assert.equal(defaults.inputFilePdfOcrDpi, 150);
    assert.equal(defaults.inputFilePdfOcrLanguage, "eng");

    process.env.CODEXCOMPAT_INPUT_FILE_PDF_OCR = "disabled";
    process.env.CODEXCOMPAT_INPUT_FILE_PDF_OCR_MAX_PAGES = "5";
    process.env.CODEXCOMPAT_INPUT_FILE_PDF_OCR_DPI = "200";
    process.env.CODEXCOMPAT_INPUT_FILE_PDF_OCR_LANGUAGE = "deu+eng";
    const configured = loadConfig({ providerBaseUrl: "https://api.deepseek.com" });
    assert.equal(configured.inputFilePdfOcr, "disabled");
    assert.equal(configured.inputFilePdfOcrMaxPages, 5);
    assert.equal(configured.inputFilePdfOcrDpi, 200);
    assert.equal(configured.inputFilePdfOcrLanguage, "deu+eng");

    const overridden = loadConfig({
      providerBaseUrl: "https://api.deepseek.com",
      inputFilePdfOcr: "tesseract",
      inputFilePdfOcrMaxPages: 1,
      inputFilePdfOcrDpi: 72,
      inputFilePdfOcrLanguage: "spa",
    });
    assert.equal(overridden.inputFilePdfOcr, "tesseract");
    assert.equal(overridden.inputFilePdfOcrMaxPages, 1);
    assert.equal(overridden.inputFilePdfOcrDpi, 72);
    assert.equal(overridden.inputFilePdfOcrLanguage, "spa");
  } finally {
    for (const [name, value] of previous.entries()) {
      if (value === undefined) delete process.env[name];
      else process.env[name] = value;
    }
  }
});

test("loadConfig reads local prompt templates from file and env JSON", () => {
  const previousFile = process.env.CODEXCOMPAT_PROMPT_TEMPLATE_FILE;
  const previousInline = process.env.CODEXCOMPAT_PROMPT_TEMPLATES;
  const stateDir = fs.mkdtempSync(path.join(os.tmpdir(), "open-codex-prompt-config-"));
  const templateFile = path.join(stateDir, "prompt-templates.json");
  fs.writeFileSync(templateFile, JSON.stringify({
    pmpt_file: { instructions: "from file" },
    pmpt_override: { instructions: "file value" },
  }));

  try {
    process.env.CODEXCOMPAT_PROMPT_TEMPLATE_FILE = templateFile;
    process.env.CODEXCOMPAT_PROMPT_TEMPLATES = JSON.stringify({
      pmpt_env: { instructions: "from env" },
      pmpt_override: { instructions: "env value" },
    });

    const config = loadConfig({ providerBaseUrl: "https://api.deepseek.com" });
    assert.deepEqual(config.localPromptTemplates.pmpt_file, { instructions: "from file" });
    assert.deepEqual(config.localPromptTemplates.pmpt_env, { instructions: "from env" });
    assert.deepEqual(config.localPromptTemplates.pmpt_override, { instructions: "env value" });
  } finally {
    if (previousFile === undefined) delete process.env.CODEXCOMPAT_PROMPT_TEMPLATE_FILE;
    else process.env.CODEXCOMPAT_PROMPT_TEMPLATE_FILE = previousFile;
    if (previousInline === undefined) delete process.env.CODEXCOMPAT_PROMPT_TEMPLATES;
    else process.env.CODEXCOMPAT_PROMPT_TEMPLATES = previousInline;
    fs.rmSync(stateDir, { recursive: true, force: true });
  }
});

test("GET /v1/models/{model} proxies direct retrieval and falls back to model list", async () => {
  await withMockProvider(async (req, res) => {
    if (req.method === "GET" && req.url === "/models/direct-model") {
      res.writeHead(200, { "content-type": "application/json" });
      res.end(JSON.stringify({
        id: "direct-model",
        object: "model",
        created: 123,
        owned_by: "provider",
      }));
      return;
    }

    if (req.method === "GET" && req.url === "/models") {
      res.writeHead(200, { "content-type": "application/json" });
      res.end(JSON.stringify({
        object: "list",
        data: [{
          id: "listed-model",
          object: "model",
          created: 456,
          owned_by: "provider-list",
        }],
      }));
      return;
    }

    res.writeHead(404, { "content-type": "application/json" });
    res.end(JSON.stringify({ error: { message: "not found" } }));
  }, async ({ bridgeAddress, requests }) => {
    const baseUrl = `http://127.0.0.1:${bridgeAddress.port}`;
    const direct = await fetch(`${baseUrl}/v1/models/direct-model`);
    assert.equal(direct.status, 200);
    assert.deepEqual(await direct.json(), {
      id: "direct-model",
      object: "model",
      created: 123,
      owned_by: "provider",
    });

    const listed = await fetch(`${baseUrl}/v1/models/listed-model`);
    assert.equal(listed.status, 200);
    assert.deepEqual(await listed.json(), {
      id: "listed-model",
      object: "model",
      created: 456,
      owned_by: "provider-list",
    });

    const localModeration = await fetch(`${baseUrl}/v1/models/omni-moderation-latest`);
    assert.equal(localModeration.status, 200);
    assert.deepEqual(await localModeration.json(), {
      id: "omni-moderation-latest",
      object: "model",
      created: 0,
      owned_by: "compatibility-bridge",
    });

    assert.equal(requests[0].req.url, "/models/direct-model");
    assert.equal(requests[1].req.url, "/models/listed-model");
    assert.equal(requests[2].req.url, "/models");
    assert.equal(requests[3].req.url, "/models/omni-moderation-latest");
    assert.equal(requests[4].req.url, "/models");
  });
});
